CREATE VIEW `ads_read_book_read_chapter_readtime_view` (`dt` COMMENT "根据createtime分区", `product_id` COMMENT "产品id", `user_id` COMMENT "用户id", `book_id` COMMENT "书籍id", `chapter_id` COMMENT "章节id", `mt` COMMENT "设备类型", `corever` COMMENT "corever", `prodid` COMMENT "产品id", `appver` COMMENT "版本号", `event` COMMENT "事件", `create_time` COMMENT "添加时间", `read_time` COMMENT "阅读时长： -s", `etl_time` COMMENT "starrocks数据注入时间")
